const input = $json ?? {};
const binary = $binary ?? {};

const rootFolderIdRaw = String(input.rootFolderId ?? '').trim();
const rootFolderId = rootFolderIdRaw || 'root';

const rawPath = String(input.folderPath ?? '').trim();
const normalizedPath = rawPath
  .replace(/^\/+|\/+$/g, '')
  .replace(/\/+/g, '/');

const segments = normalizedPath ? normalizedPath.split('/').filter(Boolean) : [];
const currentSegment = segments[0] || '';
const remainingPath = segments.length > 1 ? segments.slice(1).join('/') : '';

const explicitBinaryField = String(input.binaryFieldName ?? '').trim();
const availableBinaryFields = Object.keys(binary);
const binaryFieldName = explicitBinaryField && binary[explicitBinaryField]
  ? explicitBinaryField
  : (availableBinaryFields[0] || '');

const binaryFile = binaryFieldName ? binary[binaryFieldName] : null;
const binaryFileName = String(binaryFile?.fileName ?? '').trim();
const targetFileName = String(input.fileName ?? binaryFileName ?? '').trim() || 'uploaded-file.bin';

const rawAction = String(input.action ?? 'upsert').trim().toLowerCase();
const action = rawAction === 'get'
  ? 'get'
  : (rawAction === 'delete'
      ? 'delete'
      : (rawAction === 'list' ? 'list' : 'upsert'));

return [{
  json: {
    ...input,
    action,
    rootFolderId,
    folderPath: normalizedPath,
    currentSegment,
    remainingPath,
    baseFolderId: rootFolderId,
    binaryFieldName,
    hasBinaryFile: Boolean(binaryFile),
    targetFileName
  },
  binary
}];

const context = $('Finalize Target Context').first().json || {};
const inputItems = $input.all();

const toFileUrl = (row) => {
  const id = String(row.id || '');
  if (!id) return '';
  const mimeType = String(row.mimeType || '');
  if (mimeType === 'application/vnd.google-apps.folder') {
    return row.webViewLink || ('https://drive.google.com/drive/folders/' + id);
  }
  return row.webViewLink || ('https://drive.google.com/file/d/' + id + '/view');
};

const items = inputItems
  .map((entry) => entry.json || {})
  .filter((row) => String(row.id || '').trim().length > 0)
  .map((row) => ({
    id: String(row.id || ''),
    name: String(row.name || ''),
    mimeType: String(row.mimeType || ''),
    size: String(row.size || ''),
    webViewLink: String(row.webViewLink || ''),
    url: toFileUrl(row),
    isFolder: String(row.mimeType || '') === 'application/vnd.google-apps.folder'
  }));

return [{
  json: {
    status: 'success',
    action: 'list',
    folderId: String(context.targetFolderId || ''),
    folderUrl: String(context.targetFolderUrl || ('https://drive.google.com/drive/folders/' + (context.targetFolderId || ''))),
    itemCount: items.length,
    items
  }
}];
